export function parseArgs(argv) {
  const result = { _: [] }
  let i = 0
  while (i < argv.length) {
    const arg = argv[i]
    if (arg === '-') break
    if (arg.startsWith('---')) {
      result._.push(arg)
      i++
      continue
    }
    if (!arg.startsWith('-')) {
      result._.push(arg)
      i++
      continue
    }
    if (arg.startsWith('--') && !arg.startsWith('--=')) {
      if (i + 1 < argv.length && !argv[i + 1].startsWith '-') {
        result[arg.slice(2)] = argv[i + 1]
        i += 2
        continue
      }
      const [key, value] = arg.split('=')
      result[key] = value ? value : true
      i++
      continue
    }
    if (arg.startsWith('--=')) {
      const [key, value] = arg.slice(2).split('=')
      result[key] = value || true
      i++
      continue
    }
    result._.push(arg)
    i++
  }
  return result
}

