export function parseArgs(argv) {
  const result = { _: [] }
  let i = 0
  while (i < argv.length) {
    const arg = argv[i]
    if (arg.startsWith('-')) {
      if (arg.startsWith('---')) {
        result._.push(arg)
        i++
        continue
      }
      if (arg.includes('=')) {
        const equalsIndex = arg.indexOf('=')
        const key = arg.slice(2, equalsIndex)
        const value = arg.slice(equalsIndex + 1)
        result[key] = value || true
        i++
        continue
      }
      if (i + 1 < argv.length) {
        const next = argv[i + 1]
        if (!next.startsWith('-')) {
          result[arg.slice(2)] = next
          i += 2
          continue
        }
      }
      result[arg.slice(2)] = true
      i++
      continue
    }
    result._.push(arg)
    i++
  }
  return result
}
